export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十五點整。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越在十二點四十五分的時候被許星棠叫來了。他從舞台組借了一台備用筆電和一條傳輸線，用器材搬運的理由離開了禮堂側台。沒有人問他為什麼。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個人。兩台筆電。一張桌子。一扇漏雨的窗。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上，解密後的檔案目錄已經展開。三個資料夾。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "音訊。文件。圖片。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "先聽錄音。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點開音訊資料夾。裡面有四個檔案。檔名都是日期加編號——十年前的日期。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一個。最短的。四十三秒。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠點了播放。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個男人的聲音。不是透過專業麥克風錄的——是手機或者錄音筆放在口袋裡的那種悶悶的音質。背景有風聲。有車聲。像在戶外。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後另一個聲音進來了。也在說話。兩個人對話。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "⋯⋯材料那批，驗收單上寫的是A級防火塗料。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "實際進場的我看了。B級。外包裝貼的A級標。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第二個聲音更低。更平。像在陳述一件已經確認的事。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "差一個等級。夠不夠死人。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "看運氣。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四十三秒。到這裡斷了。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯材料被換過。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）A級防火塗料換成B級。驗收單造假。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸錄下了這段對話。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "這是誰在說話。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第一個聲音不清楚。第二個——", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我媽的調查筆記裡提過一個承包商名字。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這段錄音的日期和她筆記裡記的那次「私下確認材料」是同一天。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點開第二個檔案。兩分十一秒。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "同一個男人的聲音。這次在室內。背景有空調聲。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "付款走兩條線。正規那筆走公司帳。另一筆——現金。不入帳。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "校方那邊誰簽的。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Voice, character: "聲音", dialogue: "行政組。每次都是行政組簽。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠按了暫停。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "行政組。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "十年前行政組的負責人——", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "林主任。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "對。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點開文件資料夾。裡面是掃描件。付款紀錄。材料驗收單。承包商名單。每一份上面都有簽名——有些是林主任的，有些是承包商的，有些看不清。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這些和基座底板裡的付款紀錄能互相印證。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "基座那邊是原件。這邊是備份。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "兩邊對上——鏈條就完整了。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越從另一台筆電前面探過頭來。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "還有一個檔案。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他指著螢幕。音訊資料夾裡，第四個檔案。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "檔名不是日期編號。是文字。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "給小言。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）給小言。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他一眼。她沒有說「你準備好了嗎」。她只是把游標移到那個檔案上。等。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "播。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點了播放。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個男人的聲音。比前面幾段更近。更清楚。不是在口袋裡錄的——是對著設備說的。像他知道有人在聽。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很穩。不是慌張的。不是絕望的。是一個做了決定的人在交代事情。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "小言，如果你聽到這個，別急著相信他們說我是什麼人。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "去找證據。不要只找我。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "證據在兩個地方。你許阿姨的相機裡有一份。校史館的時間膠囊裡有一份。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuZe, character: "顧澤", dialogue: "密碼——你記得那句話。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "八秒。停了。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室裡很安靜。雨聲從窗外傳進來。筆電的散熱風扇在嗡嗡轉。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯爸。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你知道自己會被栽贓。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你提前錄好了這段。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你把證據分開藏。一份給許阿姨。一份藏在校史館。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）密碼——你記得那句話。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你一直知道我會想起來。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你一直在等。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有說話。他看著螢幕上那個播放完的波形圖。一條直線。聲音已經播完了。但那句「你記得那句話」還在房間裡迴盪，像被牆壁和書架彈了幾次才慢慢消失。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "材料齊了。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音把他拉回來。很平。很穩。像一個已經把情緒收進口袋裡的人。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "錄音。付款紀錄。驗收單。承包商名單。你爸的證詞。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "加上我媽相機裡的照片。加上基座底板的影像——今晚拍。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "加上當晚門禁和後台清場的畫面——我拍。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "全部放在一起——就是證據包。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "怎麼包。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "兩個版本。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "短版。十五秒。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "就算直播被切，也先讓所有人看到最核心的東西。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "完整版。三分鐘。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "照片、錄音、付款紀錄、你爸的備份、當晚後台畫面。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "全放進去。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把第二台筆電轉過來。螢幕上是一個最基礎的剪輯軟體。時間軸是空的。他已經建好了專案。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "舞台組的筆電裡只有這個。不是專業的。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "能剪。能加字。能貼圖。但效果——", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不需要效果。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "需要清楚。", background: Background.Chapter_8_Ch8_Act8_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們開始了。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個高中生。兩台筆電。一個舊圖書室。窗外下著雨。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有專業設備。沒有後製軟體。沒有時間。", background: Background.Chapter_8_Ch8_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "短版先做。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越打開一個黑底白字的標題畫面。打了兩行字。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「十年前南翼火災，不是顧澤縱火。」", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "字體是軟體預設的。沒有特效。沒有動畫。白字打在黑底上。像考卷上的答案。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第二段。照片對比。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從記憶卡裡拉出兩張照片。一張是校史館牆上的公開照——裁切過的。另一張是未裁切的照片。她把兩張並排放進時間軸。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "公開照裡，邵叔站在左邊，離承包商很遠。未裁切照裡，邵叔站在承包商旁邊。公開照裡看不到許母的臉。未裁切照裡，她的工作證上「許」字清晰可見。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩張照片之間，韓越打了一行字幕。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「同一張照片。裁掉的是誰？」", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第三段。付款異常。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她從解密檔案裡截了一頁付款紀錄。上面有兩條線——正規帳目和現金。簽名欄上「林」字看得見。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把它放進時間軸。加了字幕。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「材料被換過。付款走兩條線。」", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "第四段。錄音。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她截了顧澤錄的那段工程材料替換對話。四十三秒太長——她剪了最關鍵的八秒。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「差一個等級。夠不夠死人。」「看運氣。」", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "字幕打在畫面下方。白字。黑底。沒有別的。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "夠了。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "十五秒。標題、照片對比、付款異常、錄音字幕。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "就算只播這十五秒——所有人都會看見。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越按了存檔。檔名很簡單。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "短版_15秒_最終。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是專業命名。是三個高中生在時間壓力下能想到的最直接的叫法。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "完整版呢。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "一樣的方式。只是更長。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們繼續做。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "完整版三分鐘。順序是——", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十年前南翼整修資料。顧澤與許母的調查照片。工程付款異常。火災前後錄音片段。顧澤加密備份中的短證詞。最後留三十秒——給今晚的門禁、後台清場和邵叔行動畫面。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "最後三十秒今晚補。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "基座影像、門禁紀錄、邵叔在後台的畫面——這些要等今晚才能拍到。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "前面兩分半現在做好。後面三十秒留空。今晚接上。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "來得及嗎。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "23:00 前接入就行。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "閉幕直播最後素材切換。我遞交。你接線。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不是駭入。是替換。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我知道。備份線我確認過了。側台到控制台一條線。我接。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他們做了二十分鐘。沒有人說多餘的話。許星棠負責內容順序和截圖。韓越負責剪輯和字幕。顧言負責——", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我負責什麼。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我坐在這裡。看著他們把我爸的錄音、許阿姨的照片、林主任的簽名、承包商的名字——一條一條放進時間軸。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是我做的。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這是爸和許阿姨十年前開始做的。我只是——把它打開了。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十五點三十五分。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "完整版的前兩分半做好了。最後三十秒的軌道是空的。等今晚。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越把兩個檔案存好。短版和完整版。放在桌面上一個新建的資料夾裡。資料夾名——", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "證據包。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個字。沒有別的。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠把記憶卡從讀卡機裡退出來。放回相機裡。相機掛回脖子上。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "短版備份一份到備用卡。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "備用卡不放在相機裡。不放在我身上。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "放你那裡。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看向顧言。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你的口袋。最裡面那層。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言接過備用卡。很小。一張指甲蓋大小的記憶卡。他把它放進校服內側口袋——靠近胸口的位置。和第四章那張未裁切照片同一個位置。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這張卡裡是十五秒。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）十五秒。標題、照片、付款、錄音。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）就算直播被切。就算邵叔二十秒後下令關播。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這十五秒——已經出去了。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "剩下的——", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "今晚。19:30 基座拆展。你們拍底板。我接直播線。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "22:22 鐘樓停電。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你——", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著顧言。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你知道要做什麼。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "知道。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "23:00。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "證據出去。我活著。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "兩件事同時。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越合上筆電。動作很輕。像在合一本書。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "我先把設備搬回去。舞台組那邊不能太久沒人。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。把備用筆電塞進背包。拉鏈拉好。他走到門口的時候停了一下。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "顧言。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯嗯。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "22:22。你確定。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "確定。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "⋯⋯", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.HanYue, character: "韓越", dialogue: "別真的死。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.HanYue_Worried },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有等回答。推開門。走了。腳步聲在走廊裡很快地消失了。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "舊圖書室裡只剩下兩個人。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠在收拾桌面。把紙張疊好。把筆電合上。動作很穩。很慢。像在整理一個已經決定好的計畫的最後細節。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言坐在椅子上。沒有動。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著螢幕暗下去的筆電。看著自己映在黑色螢幕上的影子。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸說——去找證據。不要只找我。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我找到了。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸說——不要回頭看火，去看海上的燈。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我記起來了。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）現在——", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）去點燈。", background: Background.Chapter_8_Ch8_Act8_S1, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十五點四十分。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他站起來。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外，雨還在下。灰色的海面在遠處。看不見燈。但他知道它在那裡。", background: Background.Chapter_8_Ch8_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它一直都在。", background: Background.Chapter_8_Ch8_Act8_S1 },
];
